;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

if(! game.inLoading && events.has(4))
{
	switchFence(2, 3, "e", "open");
	switchFence(3, 1, "n", "close");
	switchFence(4, 5, "e", "open");
	switchFence(4, 2, "e", "open");
	switchFence(5, 3, "e", "close");
	switchFence(6, 6, "n", "close");
	switchFence(6, 0, "e", "close");
	switchFence(8, 3, "e", "open");
	switchFence(9, 4, "n", "close");
}

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="The switch on this floor opens all closed doors and closes all open doors."

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@se f=kacha
@wait time=800
@se f=fence
@switchfence x=2 y=3 way=e mode=switch
@switchfence x=3 y=1 way=n mode=switch
@switchfence x=4 y=5 way=e mode=switch
@switchfence x=4 y=2 way=e mode=switch
@switchfence x=5 y=3 way=e mode=switch
@switchfence x=6 y=6 way=n mode=switch
@switchfence x=6 y=0 way=e mode=switch
@switchfence x=8 y=3 way=e mode=switch
@switchfence x=9 y=4 way=n mode=switch

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@notice text="Switch to open everything"

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@se f=kacha
@wait time=800
@se f=fence
@switchfence x=2 y=3 way=e force=open
@switchfence x=3 y=1 way=n force=open
@switchfence x=4 y=2 way=e force=open
@switchfence x=4 y=5 way=e force=open
@switchfence x=5 y=3 way=e force=open
@switchfence x=6 y=6 way=n force=open
@switchfence x=6 y=0 way=e force=open
@switchfence x=8 y=3 way=e force=open
@switchfence x=9 y=4 way=n force=open
@delevent num=2
@delevent num=4

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] onObjectTrigger

@eval exp='game.fallToLowerByChute(%[map: game.map.lower])'

[eventoff]
;-------------------------------------------------------------------------------
